class PlannerOutput(BaseModel):
    """Complete documentation plan with navigation structure."""

    navigation: dict[str, str | dict] = Field(
        description="Navigation structure for index.json"
    )
    page_specs: list[PageSpec] = Field(
        description="Specifications for pages to generate"
    )

async def handle_page_reviewed(self, data: dict[str, Any]) -> None:
    """Handle page.reviewed event - decide whether to accept or retry."""
    review = CriticOutput(**review_data)

    # Determine if revision is needed
    needs_revision = False

    if review.has_hallucinations:
        if attempt < self.config.generation.max_hallucination_retries:
            needs_revision = True
            reason = "hallucinations_detected"
    elif review.score < self.config.generation.min_page_score:
        if attempt < self.config.generation.max_page_retries:
            needs_revision = True
            reason = "low_score"

    if needs_revision:
        await self.event_bus.emit("page.revision_requested", ...)
    else:
        await self.event_bus.emit("page.completed", ...)
